// Sonar - Dedupe via workflow static data + source-to-dimension tagging
// Persists seen URLs across runs (n8n static data, no external DB needed)
const staticData = $getWorkflowStaticData('global');
staticData.seenUrls = staticData.seenUrls || [];

const MAX_CACHE = 800;          // cap memory growth
const MAX_ITEMS_PER_RUN = 40;   // protect downstream LLM cost

// Source URL fragment → primary dimension hint
const dimensionMap = [
  { match: 'gcaptain.com', dim: 'maritime' },
  { match: 'maritime-executive.com', dim: 'maritime' },
  { match: 'safety4sea.com', dim: 'maritime' },
  { match: 'splash247.com', dim: 'maritime' },
  { match: 'theloadstar.com', dim: 'carrier' },
  { match: 'freightwaves.com', dim: 'carrier' },
  { match: 'container-news.com', dim: 'carrier' },
  { match: 'news.google.com', dim: 'geopolitical' },
  { match: 'gdacs.org', dim: 'weather' },
  { match: 'nhc.noaa.gov', dim: 'weather' },
  { match: 'earthquake.usgs.gov', dim: 'weather' }
];

function inferDimension(url) {
  if (!url) return 'other';
  for (const { match, dim } of dimensionMap) {
    if (url.includes(match)) return dim;
  }
  return 'other';
}

const items = $input.all();
const fresh = [];

for (const item of items) {
  const url = item.json.link || item.json.url || item.json.guid;
  if (!url) continue;
  if (staticData.seenUrls.includes(url)) continue;

  staticData.seenUrls.push(url);
  fresh.push({
    json: {
      title: item.json.title || '',
      summary: (item.json.contentSnippet || item.json.content || item.json.summary || '').slice(0, 800),
      url,
      published: item.json.pubDate || item.json.isoDate || new Date().toISOString(),
      source: item.json.creator || item.json.source || 'unknown',
      source_dimension_hint: inferDimension(url)
    }
  });
  if (fresh.length >= MAX_ITEMS_PER_RUN) break;
}

// Trim cache to last MAX_CACHE entries
if (staticData.seenUrls.length > MAX_CACHE) {
  staticData.seenUrls = staticData.seenUrls.slice(-MAX_CACHE);
}

return fresh;

