// Sonar - Parse Analyst JSON output safely
const items = $input.all();
const out = [];

for (const item of items) {
  const raw = item.json.output || item.json.text || item.json.response || JSON.stringify(item.json);
  let parsed;
  try {
    // Strip markdown fences if Claude added any
    const cleaned = String(raw).replace(/```json|```/g, '').trim();
    parsed = JSON.parse(cleaned);
  } catch (e) {
    parsed = { severity: 0, primary_dimension: 'other', parse_error: e.message, raw };
  }
  out.push({ json: parsed });
}

return out;
